class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int n = s.size();
        int max_len = 1;
        for (int l = 0; l < n; ++l) {
            int cnt = 0;
            for (int r = l + 1; r < n; ++r) {
                if (s[r] == s[r - 1]) ++cnt;
                if (cnt > 1) break;
                max_len = max(max_len, r - l + 1);
            }
        }
        return max_len;
    }
};
```
efficiency: HIGH
time complexity: O(n^2)
space complexity: O(1)
